import pytest
import requests

BASE_URL = "<base_url>"

@pytest.fixture
def patient_headers():
    return <get_patient_auth_headers>()

@pytest.fixture
def consent_payload():
    return {
        "resourceType": "Consent",
        "status": "active",
        "scope": {"coding": [{"code": "patient-privacy"}]},
        "category": [{"coding": [{"code": "LOINC-59284-0"}]}],
        "patient": {"reference": "Patient/<patient_id>"},
        "provision": {"type": "permit"}
    }

def test_grant_consent_returns_201_and_stores_resource(patient_headers, consent_payload):
    post_resp = requests.post(
        f"{BASE_URL}/Consent",
        json=consent_payload,
        headers=patient_headers
    )
    assert post_resp.status_code == 201
    consent_id = post_resp.json()["id"]
    assert consent_id

    get_resp = requests.get(
        f"{BASE_URL}/Consent/{consent_id}",
        headers=patient_headers
    )
    assert get_resp.status_code == 200
    assert get_resp.json()["status"] == "active"

