import pytest
import requests
import time

BASE_URL = "<base_url>"

@pytest.fixture
def patient_headers():
    return <get_patient_auth_headers>()

@pytest.fixture
def third_party_headers():
    return <get_third_party_auth_headers>()

@pytest.fixture
def active_consent_id(patient_headers):
    cid = <create_active_consent>(patient_headers)
    yield cid
    <cleanup_consent>(cid, patient_headers)

def test_consent_revoke_enforced_at_boundary_t0_seconds(
    patient_headers, third_party_headers, active_consent_id
):
    t_before = time.monotonic()
    revoke_resp = requests.patch(
        f"{BASE_URL}/Consent/{active_consent_id}",
        json={"status": "inactive"},
        headers=patient_headers
    )
    assert revoke_resp.status_code in (200, 204)

    access_resp = requests.get(
        f"{BASE_URL}/Patient/<patient_id>/$everything",
        headers=third_party_headers
    )
    elapsed = time.monotonic() - t_before

    assert elapsed < 5, f"Test overhead too high: {elapsed:.2f}s"
    assert access_resp.status_code == 403, (
        f"Expected 403 at t≈0s after revoke, got {access_resp.status_code}"
    )

import pytest
import requests

BASE_URL = "<base_url>"
DATA_URL = f"{BASE_URL}/Patient/<patient_id>/$everything"

@pytest.fixture
def patient_headers():
    return <get_patient_auth_headers>()

@pytest.fixture
def third_party_headers():
    return <get_third_party_auth_headers>()

@pytest.fixture
def admin_headers():
    return <get_admin_auth_headers>()

def test_consent_decision_table_status_vs_role(
    patient_headers, third_party_headers, admin_headers
):
    # Case A: active consent, third-party
    cid = <create_active_consent>(patient_headers)
    r_a = requests.get(DATA_URL, headers=third_party_headers)
    assert r_a.status_code == 200, f"Case A failed: {r_a.status_code}"

    # Case B: revoke, third-party
    requests.patch(f"{BASE_URL}/Consent/{cid}", json={"status": "inactive"}, headers=patient_headers)
    r_b = requests.get(DATA_URL, headers=third_party_headers)
    assert r_b.status_code == 403, f"Case B failed: {r_b.status_code}"

    # Case C: still revoked, admin
    r_c = requests.get(DATA_URL, headers=admin_headers)
    assert r_c.status_code == 200, f"Case C failed: {r_c.status_code}"

    <cleanup_consent>(cid, patient_headers)
